const char* HelpText::Lookup(const char* id)
{
    int lo = 0, hi = kCount - 1;
    while (lo <= hi) {
        int mid = (lo + hi) / 2;
        int c = strcmp(id, kEntries[mid].id);
        if (c == 0) return kEntries[mid].text;
        if (c < 0) hi = mid - 1; else lo = mid + 1;
    }
    return nullptr;
}
